+bool TopicPublisherROS::toPublish(const std::string& topic_name)
+{
+  auto it = _topics_to_publish.find(topic_name);
+  if (it == _topics_to_publish.end())
+  {
+    return false;
+  }
+  else
+  {
+    return it->second;
+  }
+}
